// lib/db.js
import { cacheLife, cacheTag, revalidateTag } from 'next/cache';

const syncDelayMs = 1800;

let syncRun = 0;
let activeSync = null;

let catalog = {
  lastSyncedAt: new Date('2026-07-15T08:00:00.000Z').toISOString(),
  products: [
    { id: 'sku-laptop-pro', name: 'Laptop Pro 14"', price: 1499, inventory: 42, availability: 'In stock' },
    { id: 'sku-phone-max', name: 'Phone Max', price: 999, inventory: 18, availability: 'In stock' },
    { id: 'sku-tablet-air', name: 'Tablet Air', price: 649, inventory: 0, availability: 'Backorder' },
    { id: 'sku-headphones-studio', name: 'Studio Headphones', price: 249, inventory: 67, availability: 'In stock' },
    { id: 'sku-watch-sport', name: 'Watch Sport', price: 329, inventory: 9, availability: 'Low stock' },
  ],
};

function wait(ms) {
  return new Promise((resolve) => setTimeout(resolve, ms));
}

function cloneProducts(products) {
  return products.map((product) => ({ ...product }));
}

function buildSyncedCatalog(previousCatalog) {
  syncRun += 1;

  const products = previousCatalog.products.map((product, index) => {
    const inventoryShift = ((syncRun + index) % 5) - 2;
    const inventory = Math.max(0, product.inventory + inventoryShift * 3);
    const priceDelta = ((syncRun + index) % 3) * 10;
    const price = product.price + (index % 2 === 0 ? priceDelta : -priceDelta);

    let availability = 'In stock';
    if (inventory === 0) {
      availability = 'Backorder';
    } else if (inventory < 12) {
      availability = 'Low stock';
    }

    return {
      ...product,
      inventory,
      price,
      availability,
    };
  });

  return {
    lastSyncedAt: new Date().toISOString(),
    products,
  };
}

async function readCatalogSource() {
  await wait(120);
  return {
    lastSyncedAt: catalog.lastSyncedAt,
    products: cloneProducts(catalog.products),
  };
}

export async function getCatalogProducts() {
  'use cache';
  cacheLife('hours');
  cacheTag('products');

  const snapshot = await readCatalogSource();
  return snapshot.products;
}

export async function getCatalogSummary() {
  'use cache';
  cacheLife('hours');
  cacheTag('products');

  const snapshot = await readCatalogSource();
  const totalSkus = snapshot.products.length;
  const totalInventory = snapshot.products.reduce((sum, product) => sum + product.inventory, 0);
  const lowStockCount = snapshot.products.filter((product) => product.inventory > 0 && product.inventory < 12).length;
  const backorderCount = snapshot.products.filter((product) => product.inventory === 0).length;

  return {
    lastSyncedAt: snapshot.lastSyncedAt,
    totalSkus,
    totalInventory,
    lowStockCount,
    backorderCount,
  };
}

export function triggerCatalogSync() {
  if (activeSync) {
    return false;
  }

  activeSync = (async () => {
    await wait(syncDelayMs);
    catalog = buildSyncedCatalog(catalog);
    revalidateTag('products', 'max');
  })().finally(() => {
    activeSync = null;
  });

  return true;
}


